package com.auction.server.service;

import com.auction.server.database.DatabaseManager;
import com.auction.server.repository.BidRepository;
import com.auction.server.repository.ItemRepository;
import com.auction.server.repository.WalletRepository;
import com.auction.server.repository.WalletTransactionRepository;
import com.auction.shared.constant.ItemStatusConstants;
import com.auction.shared.constant.SocketEventConstants;
import com.auction.shared.model.item.Item;
import com.auction.shared.model.payloads.BidPayload;

import java.sql.Connection;
import java.sql.SQLException;
import java.time.LocalDateTime;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;
import java.util.logging.Level;
import java.util.logging.Logger;

public class BidService {
    private static final Logger LOGGER = Logger.getLogger(BidService.class.getName());
    private static final double PRICE_EPSILON = 0.000001d;
    private static final int AUTO_BID_MAX_ROUNDS = 200;

    private final BidRepository bidRepository;
    private final ItemRepository itemRepository;
    private final AutoBidResolver autoBidResolver;
    private final WalletRepository walletRepository = new WalletRepository();
    private final WalletTransactionRepository txLogRepository = new WalletTransactionRepository();
    private static final ConcurrentMap<String, Object> ITEM_LOCKS = new ConcurrentHashMap<>();

    private boolean handleWalletMovement(Connection conn, String itemId, String bidderId, double bidPrice, String prevBidderId, double prevBidPrice) throws Exception {
        // 1. Check balance of new bidder
        double[] bidderBalances = walletRepository.getBalances(conn, bidderId);
        double bidderBalance = bidderBalances[0];

        if (bidderBalance < bidPrice) {
            LOGGER.warning(String.format("Insufficient balance: has %.2f, needs %.2f for user %s", bidderBalance, bidPrice, bidderId));
            return false;
        }

        // 2. Freeze money for the new bidder
        boolean frozeOk = walletRepository.freezeAmount(conn, bidderId, bidPrice);
        if (!frozeOk) {
            LOGGER.warning("Failed to freeze balance for user: " + bidderId);
            return false;
        }

        // 3. Log FREEZE
        txLogRepository.logFreeze(conn, bidderId, bidPrice, bidderBalance, bidderBalance - bidPrice, itemId);

        // 4. Unfreeze money for previous bidder
        if (prevBidderId != null && !prevBidderId.isBlank() && !prevBidderId.equals(bidderId)) {
            boolean unfrozeOk = walletRepository.unfreezeAmount(conn, prevBidderId, prevBidPrice);
            if (!unfrozeOk) {
                LOGGER.warning("Failed to unfreeze balance for previous leader: " + prevBidderId);
                return false;
            }

            // Log UNFREEZE
            double[] prevBal = walletRepository.getBalances(conn, prevBidderId);
            txLogRepository.logUnfreeze(conn, prevBidderId, prevBidPrice, prevBal[0] - prevBidPrice, prevBal[0], itemId);
        }

        return true;
    }

    public BidService() {
        this.bidRepository = new BidRepository();
        this.itemRepository = ItemRepository.getInstance();
        this.autoBidResolver = new AutoBidResolver(PRICE_EPSILON);
    }

    public boolean registerAutoBid(String itemId, String userId, double maxBid, double increment) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return false;
        }
        if (maxBid <= 0 || increment <= 0) {
            return false;
        }

        synchronized (getItemLock(itemId)) {
            try (Connection conn = DatabaseManager.getConnection()) {
                conn.setAutoCommit(false);

                Item item = itemRepository.findById(itemId);
                if (item == null || item.getSellerId().equals(userId)) {
                    conn.rollback();
                    return false;
                }

                // [FIX] Kiểm tra xem phiên đấu giá đã hết thời gian chưa
                LocalDateTime now = LocalDateTime.now();
                if (now.isAfter(item.getEndTime())) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: auction has ended at " + item.getEndTime());
                    return false;
                }

                double minimumPossible = item.getHighestCurrentPrice() + item.getBidStep();
                if (maxBid + PRICE_EPSILON < minimumPossible) {
                    conn.rollback();
                    return false;
                }

                boolean registered = bidRepository.upsertAutoBid(
                        conn,
                        itemId,
                        userId,
                        maxBid,
                        increment,
                        LocalDateTime.now().toString()
                );

                if (!registered) {
                    conn.rollback();
                    return false;
                }

                conn.commit();
                return true;
            } catch (SQLException e) {
                LOGGER.log(Level.SEVERE, "Failed to register auto bid", e);
                return false;
            }
        }
    }

    public boolean registerAutoBidAndMaybeBid(String itemId, String userId, double maxBid, double increment) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return false;
        }
        if (maxBid <= 0 || increment <= 0) {
            return false;
        }

        FinalBid finalBid = null;
        boolean shouldBroadcast = false;

        synchronized (getItemLock(itemId)) {
            try (Connection conn = DatabaseManager.getConnection()) {
                conn.setAutoCommit(false);

                Item item = itemRepository.findById(conn, itemId);
                if (item == null || item.getSellerId().equals(userId)) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: item not found or user is the seller for itemId " + itemId);
                    return false;
                }
                if (increment + PRICE_EPSILON < item.getBidStep()) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: increment is lower than bid step for itemId " + itemId);
                    return false;
                }
                if (!isBiddingStatusAllowed(item)) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: item status does not allow bidding for itemId " + itemId
                            + ", storedStatus=" + item.getStoredStatus()
                            + ", computedStatus=" + item.getStatus());
                    return false;
                }

                LocalDateTime now = LocalDateTime.now();
                if (now.isAfter(item.getEndTime())) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: auction has ended at " + item.getEndTime()
                            + ", current time: " + now);
                    return false;
                }
                if (now.isBefore(item.getStartTime())) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: auction has not started yet at " + item.getStartTime()
                            + ", current time: " + now);
                    return false;
                }

                boolean registered = bidRepository.upsertAutoBid(
                        conn,
                        itemId,
                        userId,
                        maxBid,
                        increment,
                        now.toString()
                );
                if (!registered) {
                    conn.rollback();
                    LOGGER.warning("Auto-bid registration rejected: failed to persist auto-bid config");
                    return false;
                }

                String currentBidderId = itemRepository.getCurrentBidderId(conn, itemId);
                double currentPrice = item.getHighestCurrentPrice();
                double immediateBidPrice = computeImmediateAutoBidPrice(currentPrice, item.getBidStep(), increment);
                LOGGER.info(String.format(
                        "[AUTO_BID_REGISTER][DECISION_INPUT] time=%s itemId=%s registeringUserId=%s dbCurrentBidderId=%s currentPrice=%.2f nextLegalBid=%.2f maxBid=%.2f bidStep=%.2f increment=%.2f",
                        LocalDateTime.now(), itemId, userId, currentBidderId, currentPrice, immediateBidPrice, maxBid, item.getBidStep(), increment));
                if (userId.equals(currentBidderId)) {
                    conn.commit();
                    LOGGER.info(String.format(
                            "[AUTO_BID_REGISTER][DECISION] time=%s itemId=%s registeringUserId=%s dbCurrentBidderId=%s decision=REGISTER_ONLY",
                            LocalDateTime.now(), itemId, userId, currentBidderId));
                    LOGGER.info("Auto-bid registered without immediate bid because user is already current bidder for itemId " + itemId);
                    return true;
                }

                if (immediateBidPrice + PRICE_EPSILON <= currentPrice || immediateBidPrice > maxBid + PRICE_EPSILON) {
                    conn.rollback();
                    LOGGER.info(String.format(
                            "[AUTO_BID_REGISTER][DECISION] time=%s itemId=%s registeringUserId=%s dbCurrentBidderId=%s decision=REJECT_MAX_TOO_LOW",
                            LocalDateTime.now(), itemId, userId, currentBidderId));
                    LOGGER.info(String.format(
                            "Auto-bid registration rejected: maxBid %.2f cannot beat current price %.2f with bidStep %.2f and increment %.2f",
                            maxBid, currentPrice, item.getBidStep(), increment));
                    return false;
                }
                LOGGER.info(String.format(
                        "[AUTO_BID_REGISTER][DECISION] time=%s itemId=%s registeringUserId=%s dbCurrentBidderId=%s decision=PLACE_IMMEDIATE_AUTO_BID",
                        LocalDateTime.now(), itemId, userId, currentBidderId));

                // Handle wallet movement before updating DB
                try {
                    if (!handleWalletMovement(conn, itemId, userId, immediateBidPrice, currentBidderId, currentPrice)) {
                        conn.rollback();
                        return false;
                    }
                } catch (Exception e) {
                    conn.rollback();
                    LOGGER.log(Level.SEVERE, "Wallet operation failed during immediate auto-bid", e);
                    return false;
                }

                String bidTime = LocalDateTime.now().toString();
                if (!bidRepository.createBid(conn, itemId, userId, immediateBidPrice, bidTime)) {
                    conn.rollback();
                    LOGGER.warning("Auto-bid registration rejected: failed to create immediate auto-bid record");
                    return false;
                }
                if (!itemRepository.updateCurrentBidder(conn, itemId, immediateBidPrice, userId)) {
                    conn.rollback();
                    LOGGER.warning("Auto-bid registration rejected: failed to update immediate auto-bid current bidder");
                    return false;
                }
                LOGGER.info(String.format("[AUTO_BID_REGISTER][IMMEDIATE_BID] time=%s itemId=%s userId=%s currentPrice=%.2f bidStep=%.2f increment=%.2f bidPrice=%.2f maxBid=%.2f",
                        LocalDateTime.now(), itemId, userId, currentPrice, item.getBidStep(), increment, immediateBidPrice, maxBid));

                finalBid = runAutoBiddingRounds(conn, itemId, userId, immediateBidPrice, bidTime);
                conn.commit();
                shouldBroadcast = true;
            } catch (SQLException e) {
                LOGGER.log(Level.SEVERE, "Failed to register auto bid and place immediate bid", e);
                return false;
            }
        }

        if (shouldBroadcast && finalBid != null) {
            broadcastNewBid(itemId, finalBid);
        }
        return true;
    }

    public com.auction.shared.model.payloads.AutoBidPayload getAutoBidStatus(String itemId, String userId) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return null;
        }

        com.auction.shared.model.payloads.AutoBidPayload activeConfig =
                bidRepository.findActiveAutoBid(itemId, userId);
        if (activeConfig != null) {
            return activeConfig;
        }

        return new com.auction.shared.model.payloads.AutoBidPayload(itemId, userId, null, null, false);
    }

    public boolean cancelAutoBid(String itemId, String userId) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return false;
        }

        return Boolean.TRUE.equals(bidRepository.deactivateAutoBidIfPresent(itemId, userId));
    }

    public boolean placeBid(String itemId, String userId, double bidPrice) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return false;
        }

        synchronized (getItemLock(itemId)) {
            try (Connection conn = DatabaseManager.getConnection()) {
                conn.setAutoCommit(false);

                Item item = itemRepository.findById(conn, itemId);
                if (item == null || item.getSellerId().equals(userId)) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: item not found or user is the seller for itemId " + itemId);
                    return false;
                }
                if (!isBiddingStatusAllowed(item)) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: item status does not allow bidding for itemId " + itemId
                            + ", storedStatus=" + item.getStoredStatus()
                            + ", computedStatus=" + item.getStatus());
                    return false;
                }

                // [FIX] Kiểm tra xem phiên đấu giá đã hết thời gian chưa
                LocalDateTime now = LocalDateTime.now();
                if (now.isAfter(item.getEndTime())) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: auction has ended at " + item.getEndTime() + ", current time: " + now);
                    return false;
                }
                if (now.isBefore(item.getStartTime())) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: auction has not started yet at " + item.getStartTime() + ", current time: " + now);
                    return false;
                }

                String lastBidder = bidRepository.findLastBidder(conn, itemId);
                if (lastBidder != null && lastBidder.equals(userId)) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: same user cannot bid consecutively");
                    return false;
                }

                double minAllowedPrice = item.getHighestCurrentPrice() + item.getBidStep();
                if (bidPrice + PRICE_EPSILON < minAllowedPrice) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: bid price " + bidPrice + " is less than minimum allowed " + minAllowedPrice);
                    return false;
                }

                // Handle wallet movement before updating DB
                try {
                    if (!handleWalletMovement(conn, itemId, userId, bidPrice, item.getCurrentTopPLayerId(), item.getHighestCurrentPrice())) {
                        conn.rollback();
                        return false;
                    }
                } catch (Exception e) {
                    conn.rollback();
                    LOGGER.log(Level.SEVERE, "Wallet operation failed during manual bid placement", e);
                    return false;
                }

                String resolvedBidTime = now.toString();
                LOGGER.info(String.format("[AUTO_BID_ROUND][MANUAL_BID] time=%s itemId=%s userId=%s itemCurrentPrice=%.2f bidStep=%.2f bidPrice=%.2f minAllowed=%.2f",
                        LocalDateTime.now(), itemId, userId, item.getHighestCurrentPrice(), item.getBidStep(), bidPrice, minAllowedPrice));
                boolean created = bidRepository.createBid(conn, itemId, userId, bidPrice, resolvedBidTime);
                if (!created) {
                    conn.rollback();
                    LOGGER.warning("Bid rejected: failed to create bid record in database");
                    return false;
                }

                if (!itemRepository.updateCurrentBidder(conn, itemId, bidPrice, userId)) {
                    conn.rollback();
                    LOGGER.warning("Bid rejected: failed to update current price and bidder in database");
                    return false;
                }

                boolean isExtended = false;
                LocalDateTime newEndTime = null;
                long secondsRemaining = java.time.temporal.ChronoUnit.SECONDS.between(now, item.getEndTime());
                if (secondsRemaining < 60 && secondsRemaining >= 0) {
                    newEndTime = now.plusSeconds(60);
                    if (!itemRepository.extendEndTime(conn, itemId, newEndTime)) {
                        conn.rollback();
                        LOGGER.warning("Bid rejected: failed to extend end time for anti-sniping");
                        return false;
                    }
                    isExtended = true;
                    LOGGER.info("Anti-sniping activated: end time extended to " + newEndTime);
                }

                FinalBid finalBid = runAutoBiddingRounds(conn, itemId, userId, bidPrice, resolvedBidTime);
                conn.commit();
                try {
                    broadcastNewBid(itemId, finalBid);
                    if (isExtended) {
                        com.auction.shared.model.payloads.AuctionExtendedPayload extendedPayload = 
                            new com.auction.shared.model.payloads.AuctionExtendedPayload(itemId, newEndTime.toString());
                        AuctionRoomManager.getInstance().broadcastToRoom(itemId, SocketEventConstants.EVENT_AUCTION_EXTENDED, extendedPayload);
                        LOGGER.fine("Broadcasted AUCTION_EXTENDED for item " + itemId);
                    }
                } catch (Exception e) {
                    LOGGER.log(Level.WARNING, "Failed to broadcast for item " + itemId, e);
                }
                return true;

            } catch (Exception e) {
                LOGGER.log(Level.SEVERE, "Exception occurred during placeBid", e);
                return false;
            }
        }
    }

    private FinalBid runAutoBiddingRounds(Connection conn,
                                          String itemId,
                                          String leadingUserId,
                                          double currentPrice,
                                          String currentBidTime) throws SQLException {
        String currentLeader = leadingUserId;
        double livePrice = currentPrice;
        String liveBidTime = currentBidTime;

        for (int round = 0; round < AUTO_BID_MAX_ROUNDS; round++) {
            LOGGER.info(String.format("[AUTO_BID_ROUND][START] time=%s itemId=%s round=%d currentLeader=%s currentPrice=%.2f",
                    LocalDateTime.now(), itemId, round, currentLeader, livePrice));
            List<BidRepository.AutoBidConfig> autoBids = bidRepository.findActiveAutoBids(conn, itemId);
            if (autoBids.isEmpty()) {
                LOGGER.info(String.format("[AUTO_BID_ROUND][STOP] time=%s itemId=%s reason=no_active_configs currentLeader=%s currentPrice=%.2f",
                        LocalDateTime.now(), itemId, currentLeader, livePrice));
                return new FinalBid(currentLeader, livePrice, liveBidTime);
            }

            AutoBidResolver.ResolvedAutoBid candidate = autoBidResolver.selectNextBid(autoBids, currentLeader, livePrice);
            if (candidate == null) {
                LOGGER.info(String.format("[AUTO_BID_ROUND][STOP] time=%s itemId=%s reason=no_valid_candidate currentLeader=%s currentPrice=%.2f",
                        LocalDateTime.now(), itemId, currentLeader, livePrice));
                return new FinalBid(currentLeader, livePrice, liveBidTime);
            }

            // 1. Check if candidate can afford it
            try {
                double[] candidateBalances = walletRepository.getBalances(conn, candidate.userId());
                if (candidateBalances[0] < candidate.bidPrice()) {
                    LOGGER.warning(String.format("[AUTO_BID_ROUND][SKIP] Insufficient funds for auto-bid user %s. Needs %.2f, has %.2f",
                            candidate.userId(), candidate.bidPrice(), candidateBalances[0]));
                    bidRepository.deactivateAutoBidIfPresent(conn, itemId, candidate.userId());
                    continue; // Skip this candidate, try others in the list
                }
            } catch (Exception e) {
                throw new SQLException("Failed to verify auto-bid candidate balance: " + e.getMessage(), e);
            }

            // 2. Perform wallet movement
            try {
                if (!handleWalletMovement(conn, itemId, candidate.userId(), candidate.bidPrice(), currentLeader, livePrice)) {
                    throw new SQLException("Failed to handle wallet movement for auto-bid candidate: " + candidate.userId());
                }
            } catch (Exception e) {
                throw new SQLException("Failed to execute wallet movement for auto-bid: " + e.getMessage(), e);
            }

            String bidTime = LocalDateTime.now().toString();
            if (!bidRepository.createBid(conn, itemId, candidate.userId(), candidate.bidPrice(), bidTime)) {
                throw new SQLException("Failed to create auto bid in database");
            }
            if (!itemRepository.updateCurrentBidder(conn, itemId, candidate.bidPrice(), candidate.userId())) {
                throw new SQLException("Failed to update current price and bidder after auto bid in database");
            }
            LOGGER.info(String.format("[AUTO_BID_ROUND][ACCEPT] time=%s itemId=%s userId=%s bidPrice=%.2f",
                    LocalDateTime.now(), itemId, candidate.userId(), candidate.bidPrice()));

            livePrice = candidate.bidPrice();
            currentLeader = candidate.userId();
            liveBidTime = bidTime;
        }

        return new FinalBid(currentLeader, livePrice, liveBidTime);
    }

    private record FinalBid(String userId, double bidPrice, String bidTime) {
    }

    private double computeImmediateAutoBidPrice(double currentPrice, double bidStep, double increment) {
        double requiredIncrement = Math.max(bidStep, increment);
        return currentPrice + requiredIncrement;
    }

    private void broadcastNewBid(String itemId, FinalBid finalBid) {
        BidPayload newBidData = new BidPayload(
                itemId,
                finalBid.userId(),
                finalBid.bidPrice(),
                finalBid.bidTime()
        );

        AuctionRoomManager.getInstance().broadcastToRoom(itemId, SocketEventConstants.EVENT_NEW_BID, newBidData);
        LOGGER.fine("Broadcasted new bid for item " + itemId);
    }

    private boolean isBiddingStatusAllowed(Item item) {
        String storedStatus = normalizeStatus(item.getStoredStatus());
        if (ItemStatusConstants.BANNED.equals(storedStatus) || ItemStatusConstants.ENDED.equals(storedStatus)) {
            return false;
        }

        String computedStatus = normalizeStatus(item.getStatus());
        return ItemStatusConstants.ONGOING.equals(computedStatus);
    }

    private String normalizeStatus(String status) {
        return status == null ? "" : status.trim().toUpperCase();
    }

    public static Object getItemLock(String itemId) {
        return ITEM_LOCKS.computeIfAbsent(itemId, ignored -> new Object());
    }

}

package com.auction.server.service;

import com.auction.server.database.DatabaseManager;
import com.auction.server.repository.BidRepository;
import com.auction.server.repository.ItemRepository;
import com.auction.server.repository.WalletRepository;
import com.auction.server.repository.WalletTransactionRepository;
import com.auction.shared.constant.ItemStatusConstants;
import com.auction.shared.constant.SocketEventConstants;
import com.auction.shared.exception.AuctionClosedException;
import com.auction.shared.exception.ConnectionException;
import com.auction.shared.exception.DataException;
import com.auction.shared.exception.InvalidBidException;
import com.auction.shared.model.item.Item;
import com.auction.shared.model.payloads.BidPayload;

import java.sql.Connection;
import java.sql.SQLException;
import java.time.LocalDateTime;
import java.util.List;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;
import java.util.logging.Level;
import java.util.logging.Logger;

public class BidService {
    private static final Logger LOGGER = Logger.getLogger(BidService.class.getName());
    private static final double PRICE_EPSILON = 0.000001d;
    private static final int AUTO_BID_MAX_ROUNDS = 200;

    private final BidRepository bidRepository;
    private final ItemRepository itemRepository;
    private final AutoBidResolver autoBidResolver;
    private final WalletRepository walletRepository = new WalletRepository();
    private final WalletTransactionRepository txLogRepository = new WalletTransactionRepository();
    private static final ConcurrentMap<String, Object> ITEM_LOCKS = new ConcurrentHashMap<>();

    private boolean handleWalletMovement(Connection conn, String itemId, String bidderId, double bidPrice, String prevBidderId, double prevBidPrice) throws Exception {
        // 1. Check balance of new bidder
        double[] bidderBalances = walletRepository.getBalances(conn, bidderId);
        double bidderBalance = bidderBalances[0];

        if (bidderBalance < bidPrice) {
            LOGGER.warning(String.format("Insufficient balance: has %.2f, needs %.2f for user %s", bidderBalance, bidPrice, bidderId));
            return false;
        }

        // 2. Freeze money for the new bidder
        boolean frozeOk = walletRepository.freezeAmount(conn, bidderId, bidPrice);
        if (!frozeOk) {
            LOGGER.warning("Failed to freeze balance for user: " + bidderId);
            return false;
        }

        // 3. Log FREEZE
        txLogRepository.logFreeze(conn, bidderId, bidPrice, bidderBalance, bidderBalance - bidPrice, itemId);

        // 4. Unfreeze money for previous bidder
        if (prevBidderId != null && !prevBidderId.isBlank() && !prevBidderId.equals(bidderId)) {
            boolean unfrozeOk = walletRepository.unfreezeAmount(conn, prevBidderId, prevBidPrice);
            if (!unfrozeOk) {
                LOGGER.warning("Failed to unfreeze balance for previous leader: " + prevBidderId);
                return false;
            }

            // Log UNFREEZE
            double[] prevBal = walletRepository.getBalances(conn, prevBidderId);
            txLogRepository.logUnfreeze(conn, prevBidderId, prevBidPrice, prevBal[0] - prevBidPrice, prevBal[0], itemId);
        }

        return true;
    }

    public BidService() {
        this.bidRepository = new BidRepository();
        this.itemRepository = ItemRepository.getInstance();
        this.autoBidResolver = new AutoBidResolver(PRICE_EPSILON);
    }

    public boolean registerAutoBid(String itemId, String userId, double maxBid, double increment) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return false;
        }
        if (maxBid <= 0 || increment <= 0) {
            return false;
        }

        synchronized (getItemLock(itemId)) {
            try (Connection conn = DatabaseManager.getConnection()) {
                conn.setAutoCommit(false);

                Item item = itemRepository.findById(itemId);
                if (item == null || item.getSellerId().equals(userId)) {
                    conn.rollback();
                    return false;
                }

                // [FIX] Kiểm tra xem phiên đấu giá đã hết thời gian chưa
                LocalDateTime now = LocalDateTime.now();
                if (now.isAfter(item.getEndTime())) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: auction has ended at " + item.getEndTime());
                    return false;
                }

                double minimumPossible = item.getHighestCurrentPrice() + item.getBidStep();
                if (maxBid + PRICE_EPSILON < minimumPossible) {
                    conn.rollback();
                    return false;
                }

                boolean registered = bidRepository.upsertAutoBid(
                        conn,
                        itemId,
                        userId,
                        maxBid,
                        increment,
                        LocalDateTime.now().toString()
                );

                if (!registered) {
                    conn.rollback();
                    return false;
                }

                conn.commit();
                return true;
            } catch (SQLException e) {
                LOGGER.log(Level.SEVERE, "Failed to register auto bid", e);
                return false;
            }
        }
    }

    public boolean registerAutoBidAndMaybeBid(String itemId, String userId, double maxBid, double increment) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return false;
        }
        if (maxBid <= 0 || increment <= 0) {
            return false;
        }

        FinalBid finalBid = null;
        boolean shouldBroadcast = false;

        synchronized (getItemLock(itemId)) {
            try (Connection conn = DatabaseManager.getConnection()) {
                conn.setAutoCommit(false);

                Item item = itemRepository.findById(conn, itemId);
                if (item == null || item.getSellerId().equals(userId)) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: item not found or user is the seller for itemId " + itemId);
                    return false;
                }
                if (increment + PRICE_EPSILON < item.getBidStep()) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: increment is lower than bid step for itemId " + itemId);
                    return false;
                }
                if (!isBiddingStatusAllowed(item)) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: item status does not allow bidding for itemId " + itemId
                            + ", storedStatus=" + item.getStoredStatus()
                            + ", computedStatus=" + item.getStatus());
                    return false;
                }

                LocalDateTime now = LocalDateTime.now();
                if (now.isAfter(item.getEndTime())) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: auction has ended at " + item.getEndTime()
                            + ", current time: " + now);
                    return false;
                }
                if (now.isBefore(item.getStartTime())) {
                    conn.rollback();
                    LOGGER.info("Auto-bid registration rejected: auction has not started yet at " + item.getStartTime()
                            + ", current time: " + now);
                    return false;
                }

                boolean registered = bidRepository.upsertAutoBid(
                        conn,
                        itemId,
                        userId,
                        maxBid,
                        increment,
                        now.toString()
                );
                if (!registered) {
                    conn.rollback();
                    LOGGER.warning("Auto-bid registration rejected: failed to persist auto-bid config");
                    return false;
                }

                String currentBidderId = itemRepository.getCurrentBidderId(conn, itemId);
                double currentPrice = item.getHighestCurrentPrice();
                double immediateBidPrice = computeImmediateAutoBidPrice(currentPrice, item.getBidStep(), increment);
                LOGGER.info(String.format(
                        "[AUTO_BID_REGISTER][DECISION_INPUT] time=%s itemId=%s registeringUserId=%s dbCurrentBidderId=%s currentPrice=%.2f nextLegalBid=%.2f maxBid=%.2f bidStep=%.2f increment=%.2f",
                        LocalDateTime.now(), itemId, userId, currentBidderId, currentPrice, immediateBidPrice, maxBid, item.getBidStep(), increment));
                if (userId.equals(currentBidderId)) {
                    conn.commit();
                    LOGGER.info(String.format(
                            "[AUTO_BID_REGISTER][DECISION] time=%s itemId=%s registeringUserId=%s dbCurrentBidderId=%s decision=REGISTER_ONLY",
                            LocalDateTime.now(), itemId, userId, currentBidderId));
                    LOGGER.info("Auto-bid registered without immediate bid because user is already current bidder for itemId " + itemId);
                    return true;
                }

                if (immediateBidPrice + PRICE_EPSILON <= currentPrice || immediateBidPrice > maxBid + PRICE_EPSILON) {
                    conn.rollback();
                    LOGGER.info(String.format(
                            "[AUTO_BID_REGISTER][DECISION] time=%s itemId=%s registeringUserId=%s dbCurrentBidderId=%s decision=REJECT_MAX_TOO_LOW",
                            LocalDateTime.now(), itemId, userId, currentBidderId));
                    LOGGER.info(String.format(
                            "Auto-bid registration rejected: maxBid %.2f cannot beat current price %.2f with bidStep %.2f and increment %.2f",
                            maxBid, currentPrice, item.getBidStep(), increment));
                    return false;
                }
                LOGGER.info(String.format(
                        "[AUTO_BID_REGISTER][DECISION] time=%s itemId=%s registeringUserId=%s dbCurrentBidderId=%s decision=PLACE_IMMEDIATE_AUTO_BID",
                        LocalDateTime.now(), itemId, userId, currentBidderId));

                // Handle wallet movement before updating DB
                try {
                    if (!handleWalletMovement(conn, itemId, userId, immediateBidPrice, currentBidderId, currentPrice)) {
                        conn.rollback();
                        return false;
                    }
                } catch (Exception e) {
                    conn.rollback();
                    LOGGER.log(Level.SEVERE, "Wallet operation failed during immediate auto-bid", e);
                    return false;
                }

                String bidTime = LocalDateTime.now().toString();
                if (!bidRepository.createBid(conn, itemId, userId, immediateBidPrice, bidTime)) {
                    conn.rollback();
                    LOGGER.warning("Auto-bid registration rejected: failed to create immediate auto-bid record");
                    return false;
                }
                if (!itemRepository.updateCurrentBidder(conn, itemId, immediateBidPrice, userId)) {
                    conn.rollback();
                    LOGGER.warning("Auto-bid registration rejected: failed to update immediate auto-bid current bidder");
                    return false;
                }
                LOGGER.info(String.format("[AUTO_BID_REGISTER][IMMEDIATE_BID] time=%s itemId=%s userId=%s currentPrice=%.2f bidStep=%.2f increment=%.2f bidPrice=%.2f maxBid=%.2f",
                        LocalDateTime.now(), itemId, userId, currentPrice, item.getBidStep(), increment, immediateBidPrice, maxBid));

                finalBid = runAutoBiddingRounds(conn, itemId, userId, immediateBidPrice, bidTime);
                conn.commit();
                shouldBroadcast = true;
            } catch (SQLException e) {
                LOGGER.log(Level.SEVERE, "Failed to register auto bid and place immediate bid", e);
                return false;
            }
        }

        if (shouldBroadcast && finalBid != null) {
            broadcastNewBid(itemId, finalBid);
        }
        return true;
    }

    public com.auction.shared.model.payloads.AutoBidPayload getAutoBidStatus(String itemId, String userId) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return null;
        }

        com.auction.shared.model.payloads.AutoBidPayload activeConfig =
                bidRepository.findActiveAutoBid(itemId, userId);
        if (activeConfig != null) {
            return activeConfig;
        }

        return new com.auction.shared.model.payloads.AutoBidPayload(itemId, userId, null, null, false);
    }

    public boolean cancelAutoBid(String itemId, String userId) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return false;
        }

        return Boolean.TRUE.equals(bidRepository.deactivateAutoBidIfPresent(itemId, userId));
    }

    public boolean placeBid(String itemId, String userId, double bidPrice) {
        if (itemId == null || itemId.isBlank() || userId == null || userId.isBlank()) {
            return false;
        }

        synchronized (getItemLock(itemId)) {
            try (Connection conn = DatabaseManager.getConnection()) {
                conn.setAutoCommit(false);

                Item item = itemRepository.findById(conn, itemId);
                if (item == null || item.getSellerId().equals(userId)) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: item not found or user is the seller for itemId " + itemId);
                    return false;
                }
                if (!isBiddingStatusAllowed(item)) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: item status does not allow bidding for itemId " + itemId
                            + ", storedStatus=" + item.getStoredStatus()
                            + ", computedStatus=" + item.getStatus());
                    return false;
                }

                // [FIX] Kiểm tra xem phiên đấu giá đã hết thời gian chưa
                LocalDateTime now = LocalDateTime.now();
                if (now.isAfter(item.getEndTime())) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: auction has ended at " + item.getEndTime() + ", current time: " + now);
                    return false;
                }
                if (now.isBefore(item.getStartTime())) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: auction has not started yet at " + item.getStartTime() + ", current time: " + now);
                    return false;
                }

                String lastBidder = bidRepository.findLastBidder(conn, itemId);
                if (lastBidder != null && lastBidder.equals(userId)) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: same user cannot bid consecutively");
                    return false;
                }

                double minAllowedPrice = item.getHighestCurrentPrice() + item.getBidStep();
                if (bidPrice + PRICE_EPSILON < minAllowedPrice) {
                    conn.rollback();
                    LOGGER.info("Bid rejected: bid price " + bidPrice + " is less than minimum allowed " + minAllowedPrice);
                    return false;
                }

                // Handle wallet movement before updating DB
                try {
                    if (!handleWalletMovement(conn, itemId, userId, bidPrice, item.getCurrentTopPLayerId(), item.getHighestCurrentPrice())) {
                        conn.rollback();
                        return false;
                    }
                } catch (Exception e) {
                    conn.rollback();
                    LOGGER.log(Level.SEVERE, "Wallet operation failed during manual bid placement", e);
                    return false;
                }

                String resolvedBidTime = now.toString();
                LOGGER.info(String.format("[AUTO_BID_ROUND][MANUAL_BID] time=%s itemId=%s userId=%s itemCurrentPrice=%.2f bidStep=%.2f bidPrice=%.2f minAllowed=%.2f",
                        LocalDateTime.now(), itemId, userId, item.getHighestCurrentPrice(), item.getBidStep(), bidPrice, minAllowedPrice));
                boolean created = bidRepository.createBid(conn, itemId, userId, bidPrice, resolvedBidTime);
                if (!created) {
                    conn.rollback();
                    LOGGER.warning("Bid rejected: failed to create bid record in database");
                    return false;
                }

                if (!itemRepository.updateCurrentBidder(conn, itemId, bidPrice, userId)) {
                    conn.rollback();
                    LOGGER.warning("Bid rejected: failed to update current price and bidder in database");
                    return false;
                }

                boolean isExtended = false;
                LocalDateTime newEndTime = null;
                long secondsRemaining = java.time.temporal.ChronoUnit.SECONDS.between(now, item.getEndTime());
                if (secondsRemaining < 60 && secondsRemaining >= 0) {
                    newEndTime = now.plusSeconds(60);
                    if (!itemRepository.extendEndTime(conn, itemId, newEndTime)) {
                        conn.rollback();
                        LOGGER.warning("Bid rejected: failed to extend end time for anti-sniping");
                        return false;
                    }
                    isExtended = true;
                    LOGGER.info("Anti-sniping activated: end time extended to " + newEndTime);
                }

                FinalBid finalBid = runAutoBiddingRounds(conn, itemId, userId, bidPrice, resolvedBidTime);
                conn.commit();
                try {
                    broadcastNewBid(itemId, finalBid);
                    if (isExtended) {
                        com.auction.shared.model.payloads.AuctionExtendedPayload extendedPayload = 
                            new com.auction.shared.model.payloads.AuctionExtendedPayload(itemId, newEndTime.toString());
                        AuctionRoomManager.getInstance().broadcastToRoom(itemId, SocketEventConstants.EVENT_AUCTION_EXTENDED, extendedPayload);
                        LOGGER.fine("Broadcasted AUCTION_EXTENDED for item " + itemId);
                    }
                } catch (Exception e) {
                    LOGGER.log(Level.WARNING, "Failed to broadcast for item " + itemId, e);
                }
                return true;

            } catch (Exception e) {
                LOGGER.log(Level.SEVERE, "Exception occurred during placeBid", e);
                return false;
            }
        }
    }

    private FinalBid runAutoBiddingRounds(Connection conn,
                                          String itemId,
                                          String leadingUserId,
                                          double currentPrice,
                                          String currentBidTime) throws SQLException {
        String currentLeader = leadingUserId;
        double livePrice = currentPrice;
        String liveBidTime = currentBidTime;

        for (int round = 0; round < AUTO_BID_MAX_ROUNDS; round++) {
            LOGGER.info(String.format("[AUTO_BID_ROUND][START] time=%s itemId=%s round=%d currentLeader=%s currentPrice=%.2f",
                    LocalDateTime.now(), itemId, round, currentLeader, livePrice));
            List<BidRepository.AutoBidConfig> autoBids = bidRepository.findActiveAutoBids(conn, itemId);
            if (autoBids.isEmpty()) {
                LOGGER.info(String.format("[AUTO_BID_ROUND][STOP] time=%s itemId=%s reason=no_active_configs currentLeader=%s currentPrice=%.2f",
                        LocalDateTime.now(), itemId, currentLeader, livePrice));
                return new FinalBid(currentLeader, livePrice, liveBidTime);
            }

            AutoBidResolver.ResolvedAutoBid candidate = autoBidResolver.selectNextBid(autoBids, currentLeader, livePrice);
            if (candidate == null) {
                LOGGER.info(String.format("[AUTO_BID_ROUND][STOP] time=%s itemId=%s reason=no_valid_candidate currentLeader=%s currentPrice=%.2f",
                        LocalDateTime.now(), itemId, currentLeader, livePrice));
                return new FinalBid(currentLeader, livePrice, liveBidTime);
            }

            // 1. Check if candidate can afford it
            try {
                double[] candidateBalances = walletRepository.getBalances(conn, candidate.userId());
                if (candidateBalances[0] < candidate.bidPrice()) {
                    LOGGER.warning(String.format("[AUTO_BID_ROUND][SKIP] Insufficient funds for auto-bid user %s. Needs %.2f, has %.2f",
                            candidate.userId(), candidate.bidPrice(), candidateBalances[0]));
                    bidRepository.deactivateAutoBidIfPresent(conn, itemId, candidate.userId());
                    continue; // Skip this candidate, try others in the list
                }
            } catch (Exception e) {
                throw new SQLException("Failed to verify auto-bid candidate balance: " + e.getMessage(), e);
            }

            // 2. Perform wallet movement
            try {
                if (!handleWalletMovement(conn, itemId, candidate.userId(), candidate.bidPrice(), currentLeader, livePrice)) {
                    throw new SQLException("Failed to handle wallet movement for auto-bid candidate: " + candidate.userId());
                }
            } catch (Exception e) {
                throw new SQLException("Failed to execute wallet movement for auto-bid: " + e.getMessage(), e);
            }

            String bidTime = LocalDateTime.now().toString();
            if (!bidRepository.createBid(conn, itemId, candidate.userId(), candidate.bidPrice(), bidTime)) {
                throw new SQLException("Failed to create auto bid in database");
            }
            if (!itemRepository.updateCurrentBidder(conn, itemId, candidate.bidPrice(), candidate.userId())) {
                throw new SQLException("Failed to update current price and bidder after auto bid in database");
            }
            LOGGER.info(String.format("[AUTO_BID_ROUND][ACCEPT] time=%s itemId=%s userId=%s bidPrice=%.2f",
                    LocalDateTime.now(), itemId, candidate.userId(), candidate.bidPrice()));

            livePrice = candidate.bidPrice();
            currentLeader = candidate.userId();
            liveBidTime = bidTime;
        }

        return new FinalBid(currentLeader, livePrice, liveBidTime);
    }

    private record FinalBid(String userId, double bidPrice, String bidTime) {
    }

    private double computeImmediateAutoBidPrice(double currentPrice, double bidStep, double increment) {
        double requiredIncrement = Math.max(bidStep, increment);
        return currentPrice + requiredIncrement;
    }

    private void broadcastNewBid(String itemId, FinalBid finalBid) {
        BidPayload newBidData = new BidPayload(
                itemId,
                finalBid.userId(),
                finalBid.bidPrice(),
                finalBid.bidTime()
        );

        AuctionRoomManager.getInstance().broadcastToRoom(itemId, SocketEventConstants.EVENT_NEW_BID, newBidData);
        LOGGER.fine("Broadcasted new bid for item " + itemId);
    }

    private boolean isBiddingStatusAllowed(Item item) {
        String storedStatus = normalizeStatus(item.getStoredStatus());
        if (ItemStatusConstants.BANNED.equals(storedStatus) || ItemStatusConstants.ENDED.equals(storedStatus)) {
            return false;
        }

        String computedStatus = normalizeStatus(item.getStatus());
        return ItemStatusConstants.ONGOING.equals(computedStatus);
    }

    private String normalizeStatus(String status) {
        return status == null ? "" : status.trim().toUpperCase();
    }

    public static Object getItemLock(String itemId) {
        return ITEM_LOCKS.computeIfAbsent(itemId, ignored -> new Object());
    }

}

package com.auction.server.controller;

import com.auction.server.service.AuctionRoomManager;
import com.auction.server.service.BidService;
import com.auction.shared.constant.SocketEventConstants;
import com.auction.shared.exception.AuctionException;
import com.auction.shared.message.RequestMessage;
import com.auction.shared.message.ResponseMessage;
import com.auction.shared.model.payloads.AutoBidPayload;
import com.auction.shared.model.payloads.BidPayload;
import com.auction.shared.model.payloads.RoomPayload;
import com.auction.shared.util.LocalDateTimeAdapter;
import com.google.gson.Gson;
import com.google.gson.GsonBuilder;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.net.Socket;
import java.nio.charset.StandardCharsets;
import java.time.LocalDateTime;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ClientHandler implements Runnable {
    private static final Logger LOGGER = Logger.getLogger(ClientHandler.class.getName());

    private Socket clientSocket;
    private PrintWriter out;
    private BufferedReader in;

    private Gson gson = new GsonBuilder()
            .registerTypeAdapter(LocalDateTime.class, new LocalDateTimeAdapter())
            .create();

    private String currentRoomId = null;
    private String username = "unknown";

    private AuctionRoomManager roomManager = AuctionRoomManager.getInstance();
    private BidService bidService = new BidService();


    public ClientHandler() {
    }

    public ClientHandler(Socket socket) {
        this.clientSocket = socket;
        try {
            this.out = new PrintWriter(clientSocket.getOutputStream(), true);
            this.in = new BufferedReader(new InputStreamReader(socket.getInputStream(), StandardCharsets.UTF_8));

        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Error initializing ClientHandler streams", e);
        }
    }

    public synchronized void sendMessage(String jsonMessage) {
        if (out != null) {
            out.println(jsonMessage);
        }
    }

    @Override
    public void run() {
        try {
            String jsonRequest;
            while ((jsonRequest = in.readLine()) != null) {
                RequestMessage request = gson.fromJson(jsonRequest, RequestMessage.class);
                if (request == null || request.getAction() == null) {
                    LOGGER.warning("Ignoring invalid socket request from " + username);
                    continue;
                }
                ResponseMessage responseMessage = new ResponseMessage();
                String jsonPayload = request.getPayload();
                switch (request.getAction()) {
                    case BID -> {
                        bidAction(jsonPayload, responseMessage);
                        sendIfHasStatus(responseMessage);
                    }
                    case JOIN_ROOM -> joinRoomAction(jsonPayload, responseMessage);
                    case LEAVE_ROOM -> leaveRoomAction();
                    case AUTO_BID_REGISTER -> {
                        autoBidRegisterAction(jsonPayload, responseMessage);
                        sendIfHasStatus(responseMessage);
                    }
                    case GET_AUTO_BID_STATUS -> {
                        getAutoBidStatusAction(jsonPayload, responseMessage);
                        sendIfHasStatus(responseMessage);
                    }
                    case CANCEL_AUTO_BID -> {
                        cancelAutoBidAction(jsonPayload, responseMessage);
                        sendIfHasStatus(responseMessage);
                    }
                    default -> {

                    }
                }

            }
        } catch (IOException e) {
            LOGGER.info("Client disconnected: " + username);
        } catch (RuntimeException e) {
            LOGGER.log(Level.SEVERE, "Unexpected socket handler error for client " + username, e);
        } finally {
            closeResources();
        }
    }

    private void sendIfHasStatus(ResponseMessage responseMessage) {
        if (responseMessage.getStatus() != null) {
            sendMessage(gson.toJson(responseMessage));
        }
    }

    private void closeResources() {
        try {
            com.auction.server.MainServer.activeClients.remove(this);
            roomManager.removeClientFromAllRooms(this);
            if (in != null) in.close();
            if (out != null) out.close();
            if (clientSocket != null) clientSocket.close();
        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Error closing ClientHandler resources", e);
        } finally {
            in = null;
            out = null;
            clientSocket = null;
        }
    }

    private void joinRoomAction(String jsonPayload, ResponseMessage responseMessage) {
        try {
            RoomPayload roomPayload = gson.fromJson(jsonPayload, RoomPayload.class);
            if (roomPayload == null || roomPayload.getItemId() == null || roomPayload.getItemId().isBlank()) {
                responseMessage.setStatus(SocketEventConstants.STATUS_JOIN_ROOM_FAIL);
                responseMessage.setMessage("Invalid room payload");
                sendMessage(gson.toJson(responseMessage));
                return;
            }
            this.username = roomPayload.getToken();
            LOGGER.fine("UserId: " + roomPayload.getToken() + " joining ItemId: " + roomPayload.getItemId());

            if (currentRoomId != null && !currentRoomId.equals(roomPayload.getItemId())) {
                roomManager.leaveRoom(currentRoomId, this);
            }
            currentRoomId = roomPayload.getItemId();
            roomManager.joinRoom(currentRoomId, this);
            responseMessage.setStatus(SocketEventConstants.STATUS_JOIN_ROOM_SUCCESS);
            responseMessage.setMessage("Joined room successfully");
            sendMessage(gson.toJson(responseMessage));
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to join room", e);
            responseMessage.setStatus(SocketEventConstants.STATUS_JOIN_ROOM_FAIL);
            responseMessage.setMessage("Failed to join room");
            sendMessage(gson.toJson(responseMessage));
        }
    }

    private void leaveRoomAction() {
        if (currentRoomId != null) {
            roomManager.leaveRoom(currentRoomId, this);
            currentRoomId = null;
        }
    }

    private boolean bidAction(String payload, ResponseMessage response) {
        try {
            BidPayload bidData = gson.fromJson(payload, BidPayload.class);
            LOGGER.fine("Received bid action");

            if (bidData == null || bidData.getItemId() == null || bidData.getUserId() == null || bidData.getBidPrice() == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Thông tin bid không hợp lệ: thiếu itemId, userId hoặc bidPrice");
                LOGGER.warning("Invalid bid payload received");
                return true;
            }

            // Kiểm tra giá bid có hợp lệ không
            if (bidData.getBidPrice() <= 0) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Giá bid phải lớn hơn 0");
                LOGGER.warning("Invalid bid price: " + bidData.getBidPrice());
                return true;
            }

            boolean created = bidService.placeBid(
                    bidData.getItemId(),
                    bidData.getUserId(),
                    bidData.getBidPrice()
            );

            if (created) {
                LOGGER.info("Bid placed successfully for item " + bidData.getItemId() + " by user " + bidData.getUserId());
            } else {
                LOGGER.warning("Failed to place bid for item " + bidData.getItemId());
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Không thể đặt giá. Vui lòng kiểm tra giá bid, thời gian phiên, hoặc số dư tài khoản");
            }

            return true;
        } catch (AuctionException e) {
            LOGGER.log(Level.WARNING, "Auction error during bid: " + e.getMessage());
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi đấu giá: " + e.getMessage());
            return true;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing bid action", e);
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi khi xử lý bid: Vui lòng thử lại sau");
            return true;
        }
    }

    private boolean autoBidRegisterAction(String payload, ResponseMessage response) {
        try {
            AutoBidPayload autoBidData = gson.fromJson(payload, AutoBidPayload.class);

            if (autoBidData == null
                    || autoBidData.getItemId() == null
                    || autoBidData.getUserId() == null
                    || autoBidData.getMaxBid() == null
                    || autoBidData.getIncrement() == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Thông tin auto-bid không hợp lệ: thiếu các trường bắt buộc");
                LOGGER.warning("Invalid auto-bid payload received");
                return true;
            }

            // Kiểm tra các tham số
            if (autoBidData.getMaxBid() <= 0 || autoBidData.getIncrement() <= 0) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Giá tối đa và bước tăng phải lớn hơn 0");
                LOGGER.warning("Invalid auto-bid parameters");
                return true;
            }

            boolean created = bidService.registerAutoBidAndMaybeBid(
                    autoBidData.getItemId(),
                    autoBidData.getUserId(),
                    autoBidData.getMaxBid(),
                    autoBidData.getIncrement()
            );

            if (created) {
                response.setStatus(SocketEventConstants.STATUS_SUCCESS);
                response.setMessage("Đăng ký auto-bid thành công");
                LOGGER.info("Auto-bid registered successfully");
            } else {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Không thể đăng ký auto-bid. Vui lòng kiểm tra giá tối đa, phiên đấu giá hoặc số dư");
                LOGGER.warning("Failed to register auto-bid");
            }

            return true;
        } catch (AuctionException e) {
            LOGGER.log(Level.WARNING, "Auction error during auto-bid registration: " + e.getMessage());
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi đấu giá: " + e.getMessage());
            return true;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing auto-bid register action", e);
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi khi đăng ký auto-bid: Vui lòng thử lại sau");
            return true;
        }
    }

    private boolean getAutoBidStatusAction(String payload, ResponseMessage response) {
        try {
            AutoBidPayload autoBidData = gson.fromJson(payload, AutoBidPayload.class);

            if (autoBidData == null
                    || autoBidData.getItemId() == null
                    || autoBidData.getUserId() == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Thông tin không hợp lệ: thiếu itemId hoặc userId");
                LOGGER.warning("Invalid get auto-bid status payload");
                return true;
            }

            AutoBidPayload autoBidStatus = bidService.getAutoBidStatus(
                    autoBidData.getItemId(),
                    autoBidData.getUserId()
            );

            if (autoBidStatus == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage(SocketEventConstants.EVENT_AUTO_BID_STATUS);
                LOGGER.warning("Failed to retrieve auto-bid status");
                return true;
            }

            response.setStatus(SocketEventConstants.STATUS_SUCCESS);
            response.setMessage(SocketEventConstants.EVENT_AUTO_BID_STATUS);
            response.setData(autoBidStatus);
            return true;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing get auto-bid status action", e);
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi khi lấy trạng thái auto-bid: Vui lòng thử lại sau");
            return true;
        }
    }

    private boolean cancelAutoBidAction(String payload, ResponseMessage response) {
        AutoBidPayload autoBidData = gson.fromJson(payload, AutoBidPayload.class);

        if (autoBidData == null
                || autoBidData.getItemId() == null
                || autoBidData.getUserId() == null) {
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage(SocketEventConstants.EVENT_AUTO_BID_CANCELLED);
            return true;
        }
        LOGGER.info(String.format("[AUTO_BID_CANCEL][SERVER_RECEIVE] time=%s itemId=%s userId=%s",
                LocalDateTime.now(), autoBidData.getItemId(), autoBidData.getUserId()));

        boolean cancelled = bidService.cancelAutoBid(
                autoBidData.getItemId(),
                autoBidData.getUserId()
        );

        if (!cancelled) {
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage(SocketEventConstants.EVENT_AUTO_BID_CANCELLED);
            return true;
        }

        response.setStatus(SocketEventConstants.STATUS_SUCCESS);
        response.setMessage(SocketEventConstants.EVENT_AUTO_BID_CANCELLED);
        response.setData(new AutoBidPayload(
                autoBidData.getItemId(),
                autoBidData.getUserId(),
                null,
                null,
                false
        ));
        return true;
    }

    public String getUsername() {
        return username;
    }
}

package com.auction.server.controller;

import com.auction.server.service.AuctionRoomManager;
import com.auction.server.service.BidService;
import com.auction.shared.constant.SocketEventConstants;
import com.auction.shared.exception.AuctionException;
import com.auction.shared.message.RequestMessage;
import com.auction.shared.message.ResponseMessage;
import com.auction.shared.model.payloads.AutoBidPayload;
import com.auction.shared.model.payloads.BidPayload;
import com.auction.shared.model.payloads.RoomPayload;
import com.auction.shared.util.LocalDateTimeAdapter;
import com.google.gson.Gson;
import com.google.gson.GsonBuilder;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.net.Socket;
import java.nio.charset.StandardCharsets;
import java.time.LocalDateTime;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ClientHandler implements Runnable {
    private static final Logger LOGGER = Logger.getLogger(ClientHandler.class.getName());

    private Socket clientSocket;
    private PrintWriter out;
    private BufferedReader in;

    private Gson gson = new GsonBuilder()
            .registerTypeAdapter(LocalDateTime.class, new LocalDateTimeAdapter())
            .create();

    private String currentRoomId = null;
    private String username = "unknown";

    private AuctionRoomManager roomManager = AuctionRoomManager.getInstance();
    private BidService bidService = new BidService();


    public ClientHandler() {
    }

    public ClientHandler(Socket socket) {
        this.clientSocket = socket;
        try {
            this.out = new PrintWriter(clientSocket.getOutputStream(), true);
            this.in = new BufferedReader(new InputStreamReader(socket.getInputStream(), StandardCharsets.UTF_8));

        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Error initializing ClientHandler streams", e);
        }
    }

    public synchronized void sendMessage(String jsonMessage) {
        if (out != null) {
            out.println(jsonMessage);
        }
    }

    @Override
    public void run() {
        try {
            String jsonRequest;
            while ((jsonRequest = in.readLine()) != null) {
                RequestMessage request = gson.fromJson(jsonRequest, RequestMessage.class);
                if (request == null || request.getAction() == null) {
                    LOGGER.warning("Ignoring invalid socket request from " + username);
                    continue;
                }
                ResponseMessage responseMessage = new ResponseMessage();
                String jsonPayload = request.getPayload();
                switch (request.getAction()) {
                    case BID -> {
                        bidAction(jsonPayload, responseMessage);
                        sendIfHasStatus(responseMessage);
                    }
                    case JOIN_ROOM -> joinRoomAction(jsonPayload, responseMessage);
                    case LEAVE_ROOM -> leaveRoomAction();
                    case AUTO_BID_REGISTER -> {
                        autoBidRegisterAction(jsonPayload, responseMessage);
                        sendIfHasStatus(responseMessage);
                    }
                    case GET_AUTO_BID_STATUS -> {
                        getAutoBidStatusAction(jsonPayload, responseMessage);
                        sendIfHasStatus(responseMessage);
                    }
                    case CANCEL_AUTO_BID -> {
                        cancelAutoBidAction(jsonPayload, responseMessage);
                        sendIfHasStatus(responseMessage);
                    }
                    default -> {

                    }
                }

            }
        } catch (IOException e) {
            LOGGER.info("Client disconnected: " + username);
        } catch (RuntimeException e) {
            LOGGER.log(Level.SEVERE, "Unexpected socket handler error for client " + username, e);
        } finally {
            closeResources();
        }
    }

    private void sendIfHasStatus(ResponseMessage responseMessage) {
        if (responseMessage.getStatus() != null) {
            sendMessage(gson.toJson(responseMessage));
        }
    }

    private void closeResources() {
        try {
            com.auction.server.MainServer.activeClients.remove(this);
            roomManager.removeClientFromAllRooms(this);
            if (in != null) in.close();
            if (out != null) out.close();
            if (clientSocket != null) clientSocket.close();
        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Error closing ClientHandler resources", e);
        } finally {
            in = null;
            out = null;
            clientSocket = null;
        }
    }

    private void joinRoomAction(String jsonPayload, ResponseMessage responseMessage) {
        try {
            RoomPayload roomPayload = gson.fromJson(jsonPayload, RoomPayload.class);
            if (roomPayload == null || roomPayload.getItemId() == null || roomPayload.getItemId().isBlank()) {
                responseMessage.setStatus(SocketEventConstants.STATUS_JOIN_ROOM_FAIL);
                responseMessage.setMessage("Invalid room payload");
                sendMessage(gson.toJson(responseMessage));
                return;
            }
            this.username = roomPayload.getToken();
            LOGGER.fine("UserId: " + roomPayload.getToken() + " joining ItemId: " + roomPayload.getItemId());

            if (currentRoomId != null && !currentRoomId.equals(roomPayload.getItemId())) {
                roomManager.leaveRoom(currentRoomId, this);
            }
            currentRoomId = roomPayload.getItemId();
            roomManager.joinRoom(currentRoomId, this);
            responseMessage.setStatus(SocketEventConstants.STATUS_JOIN_ROOM_SUCCESS);
            responseMessage.setMessage("Joined room successfully");
            sendMessage(gson.toJson(responseMessage));
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to join room", e);
            responseMessage.setStatus(SocketEventConstants.STATUS_JOIN_ROOM_FAIL);
            responseMessage.setMessage("Failed to join room");
            sendMessage(gson.toJson(responseMessage));
        }
    }

    private void leaveRoomAction() {
        if (currentRoomId != null) {
            roomManager.leaveRoom(currentRoomId, this);
            currentRoomId = null;
        }
    }

    private boolean bidAction(String payload, ResponseMessage response) {
        try {
            BidPayload bidData = gson.fromJson(payload, BidPayload.class);
            LOGGER.fine("Received bid action");

            if (bidData == null || bidData.getItemId() == null || bidData.getUserId() == null || bidData.getBidPrice() == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Thông tin bid không hợp lệ: thiếu itemId, userId hoặc bidPrice");
                LOGGER.warning("Invalid bid payload received");
                return true;
            }

            // Kiểm tra giá bid có hợp lệ không
            if (bidData.getBidPrice() <= 0) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Giá bid phải lớn hơn 0");
                LOGGER.warning("Invalid bid price: " + bidData.getBidPrice());
                return true;
            }

            boolean created = bidService.placeBid(
                    bidData.getItemId(),
                    bidData.getUserId(),
                    bidData.getBidPrice()
            );

            if (created) {
                LOGGER.info("Bid placed successfully for item " + bidData.getItemId() + " by user " + bidData.getUserId());
            } else {
                LOGGER.warning("Failed to place bid for item " + bidData.getItemId());
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Không thể đặt giá. Vui lòng kiểm tra giá bid, thời gian phiên, hoặc số dư tài khoản");
            }

            return true;
        } catch (AuctionException e) {
            LOGGER.log(Level.WARNING, "Auction error during bid: " + e.getMessage());
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi đấu giá: " + e.getMessage());
            return true;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing bid action", e);
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi khi xử lý bid: Vui lòng thử lại sau");
            return true;
        }
    }

    private boolean autoBidRegisterAction(String payload, ResponseMessage response) {
        try {
            AutoBidPayload autoBidData = gson.fromJson(payload, AutoBidPayload.class);

            if (autoBidData == null
                    || autoBidData.getItemId() == null
                    || autoBidData.getUserId() == null
                    || autoBidData.getMaxBid() == null
                    || autoBidData.getIncrement() == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Thông tin auto-bid không hợp lệ: thiếu các trường bắt buộc");
                LOGGER.warning("Invalid auto-bid payload received");
                return true;
            }

            // Kiểm tra các tham số
            if (autoBidData.getMaxBid() <= 0 || autoBidData.getIncrement() <= 0) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Giá tối đa và bước tăng phải lớn hơn 0");
                LOGGER.warning("Invalid auto-bid parameters");
                return true;
            }

            boolean created = bidService.registerAutoBidAndMaybeBid(
                    autoBidData.getItemId(),
                    autoBidData.getUserId(),
                    autoBidData.getMaxBid(),
                    autoBidData.getIncrement()
            );

            if (created) {
                response.setStatus(SocketEventConstants.STATUS_SUCCESS);
                response.setMessage("Đăng ký auto-bid thành công");
                LOGGER.info("Auto-bid registered successfully");
            } else {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Không thể đăng ký auto-bid. Vui lòng kiểm tra giá tối đa, phiên đấu giá hoặc số dư");
                LOGGER.warning("Failed to register auto-bid");
            }

            return true;
        } catch (AuctionException e) {
            LOGGER.log(Level.WARNING, "Auction error during auto-bid registration: " + e.getMessage());
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi đấu giá: " + e.getMessage());
            return true;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing auto-bid register action", e);
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi khi đăng ký auto-bid: Vui lòng thử lại sau");
            return true;
        }
    }

    private boolean getAutoBidStatusAction(String payload, ResponseMessage response) {
        try {
            AutoBidPayload autoBidData = gson.fromJson(payload, AutoBidPayload.class);

            if (autoBidData == null
                    || autoBidData.getItemId() == null
                    || autoBidData.getUserId() == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Thông tin không hợp lệ: thiếu itemId hoặc userId");
                LOGGER.warning("Invalid get auto-bid status payload");
                return true;
            }

            AutoBidPayload autoBidStatus = bidService.getAutoBidStatus(
                    autoBidData.getItemId(),
                    autoBidData.getUserId()
            );

            if (autoBidStatus == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage(SocketEventConstants.EVENT_AUTO_BID_STATUS);
                LOGGER.warning("Failed to retrieve auto-bid status");
                return true;
            }

            response.setStatus(SocketEventConstants.STATUS_SUCCESS);
            response.setMessage(SocketEventConstants.EVENT_AUTO_BID_STATUS);
            response.setData(autoBidStatus);
            return true;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing get auto-bid status action", e);
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi khi lấy trạng thái auto-bid: Vui lòng thử lại sau");
            return true;
        }
    }

    private boolean cancelAutoBidAction(String payload, ResponseMessage response) {
        try {
            AutoBidPayload autoBidData = gson.fromJson(payload, AutoBidPayload.class);

            if (autoBidData == null
                    || autoBidData.getItemId() == null
                    || autoBidData.getUserId() == null) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Thông tin không hợp lệ: thiếu itemId hoặc userId");
                LOGGER.warning("Invalid cancel auto-bid payload");
                return true;
            }

            LOGGER.info(String.format("[AUTO_BID_CANCEL][SERVER_RECEIVE] time=%s itemId=%s userId=%s",
                    LocalDateTime.now(), autoBidData.getItemId(), autoBidData.getUserId()));

            boolean cancelled = bidService.cancelAutoBid(
                    autoBidData.getItemId(),
                    autoBidData.getUserId()
            );

            if (!cancelled) {
                response.setStatus(SocketEventConstants.STATUS_FAIL);
                response.setMessage("Không thể hủy auto-bid");
                LOGGER.warning("Failed to cancel auto-bid");
                return true;
            }

            response.setStatus(SocketEventConstants.STATUS_SUCCESS);
            response.setMessage(SocketEventConstants.EVENT_AUTO_BID_CANCELLED);
            response.setData(new AutoBidPayload(
                    autoBidData.getItemId(),
                    autoBidData.getUserId(),
                    null,
                    null,
                    false
            ));
            LOGGER.info("Auto-bid cancelled successfully");
            return true;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing cancel auto-bid action", e);
            response.setStatus(SocketEventConstants.STATUS_FAIL);
            response.setMessage("Lỗi khi hủy auto-bid: Vui lòng thử lại sau");
            return true;
        }
    }

    public String getUsername() {
        return username;
    }
}
